  1→/* ─── Onboarding Wizard ──────────────────────────────────── */
  2→
  3→/* Overlay */
  4→.onboarding-wizard-overlay {
  5→    position: fixed;
  6→    inset: 0;
  7→    display: flex;
  8→    justify-content: center;
  9→    align-items: center;
 10→    background-color: var(--bg-backdrop-heavy);
 11→    backdrop-filter: blur(8px);
 12→    -webkit-backdrop-filter: blur(8px);
 13→    z-index: 140;
 14→}
 15→
 16→/* Card */
 17→.onboarding-wizard-card {
 18→    display: flex;
 19→    flex-direction: column;
 20→    align-items: center;
 21→    width: 100%;
 22→    max-width: 500px;
 23→    max-height: 90vh;
 24→    background: var(--bg-card);
 25→    border: 1px solid var(--border-card);
 26→    box-shadow: var(--shadow-modal);
 27→    border-radius: 16px;
 28→    padding: 28px 28px 32px;
 29→    overflow-y: auto;
 30→    overflow-x: hidden;
 31→}
 32→
 33→/* Content wrapper */
 34→.onboarding-wizard-content {
 35→    width: 100%;
 36→    position: relative;
 37→    overflow: hidden;
 38→}
 39→
 40→.onboarding-step-wrapper {
 41→    width: 100%;
 42→}
 43→
 44→/* ─── Progress Bar ───────────────────────────────────────── */
 45→
 46→.onboarding-progress-bar {
 47→    display: flex;
 48→    align-items: center;
 49→    justify-content: center;
 50→    gap: 0;
 51→    margin-bottom: 24px;
 52→    width: 100%;
 53→    max-width: 220px;
 54→}
 55→
 56→.onboarding-progress-dot-wrapper {
 57→    display: flex;
 58→    align-items: center;
 59→}
 60→
 61→.onboarding-progress-dot {
 62→    position: relative;
 63→    width: 10px;
 64→    height: 10px;
 65→    border-radius: 50%;
 66→    background: var(--bg-hover);
 67→    border: 1.5px solid var(--border-card);
 68→    transition: background-color 0.3s ease, border-color 0.3s ease;
 69→    flex-shrink: 0;
 70→}
 71→
 72→.onboarding-progress-dot.active {
 73→    background: var(--accent-amber, #D4A853);
 74→    border-color: var(--accent-amber, #D4A853);
 75→}
 76→
 77→.onboarding-progress-indicator {
 78→    position: absolute;
 79→    inset: -2px;
 80→    border-radius: 50%;
 81→    border: 2px solid var(--accent-amber, #D4A853);
 82→    box-shadow: 0 0 8px rgba(212, 168, 83, 0.3);
 83→}
 84→
 85→.onboarding-progress-line {
 86→    width: 32px;
 87→    height: 2px;
 88→    background: var(--border-card);
 89→    transition: background-color 0.3s ease;
 90→}
 91→
 92→.onboarding-progress-line.filled {
 93→    background: var(--accent-amber, #D4A853);
 94→}
 95→
 96→/* ─── Step Common ────────────────────────────────────────── */
 97→
 98→.onboarding-step {
 99→    display: flex;
100→    flex-direction: column;
101→    align-items: center;
102→    position: relative;
103→    width: 100%;
104→    gap: 8px;
105→}
106→
107→.onboarding-step-title {
108→    font-family: "Playfair Display", Georgia, serif;
109→    font-size: 1.5rem;
110→    font-weight: 700;
111→    color: var(--text-heading);
112→    margin: 0;
113→    text-align: center;
114→}
115→
116→.onboarding-step-subtitle {
117→    font-family: "Lora", Georgia, serif;
118→    font-style: italic;
119→    font-size: 0.95rem;
120→    line-height: 1.5;
121→    color: var(--text-body);
122→    margin: 0 0 8px;
123→    text-align: center;
124→}
125→
126→.onboarding-back-btn {
127→    position: absolute;
128→    top: 0;
129→    left: 0;
130→    display: flex;
131→    align-items: center;
132→    justify-content: center;
133→    width: 32px;
134→    height: 32px;
135→    border-radius: 50%;
136→    border: none;
137→    background: transparent;
138→    color: var(--text-muted);
139→    cursor: pointer;
140→    transition: background-color 0.15s ease, color 0.15s ease;
141→}
142→
143→.onboarding-back-btn:hover {
144→    background: var(--bg-hover);
145→    color: var(--text-secondary);
146→}
147→
148→/* ─── CTA Buttons ────────────────────────────────────────── */
149→
150→.onboarding-cta-primary {
