358→
359→.welcome-step .onboarding-step-subtitle {
360→    font-size: 1rem;
361→    margin-bottom: 24px;
362→    z-index: 1;
363→}
364→
365→.welcome-step .onboarding-cta-primary {
366→    max-width: 280px;
367→    z-index: 1;
