391→
392→/* ─── Profile Setup Step ─────────────────────────────────── */
393→
394→.profile-setup-step {
395→    padding: 8px 0 0;
396→}
397→
398→.profile-setup-form {
399→    display: flex;
400→    flex-direction: column;
401→    gap: 14px;
402→    width: 100%;
403→    margin-top: 8px;
404→}
405→
406→.profile-setup-avatar-container {
407→    display: flex;
408→    justify-content: center;
409→    margin: 8px 0;
410→}
411→
412→.profile-setup-avatar-wrapper {
413→    position: relative;
414→    width: 90px;
415→    height: 90px;
416→    cursor: pointer;
