442→/* ─── Interests Step ─────────────────────────────────────── */
443→
444→.interests-step {
445→    padding: 8px 0 0;
446→}
447→
448→.interests-topic-grid {
449→    display: flex;
450→    flex-wrap: wrap;
451→    gap: 8px;
452→    justify-content: center;
453→    margin: 8px 0 16px;
